export const updateCourse = (
    courseId: string,
    updateCourseBody: UpdateCourseBody,
 options?: SecondParameter<typeof customInstance>,) => {
      
      const formData = new FormData();
if(updateCourseBody.title !== undefined) {
 formData.append('title', updateCourseBody.title)
 }
if(updateCourseBody.description !== undefined) {
 formData.append('description', updateCourseBody.description)
 }
if(updateCourseBody.price !== undefined) {
 formData.append('price', updateCourseBody.price.toString())
 }
formData.append('renewalPrice', updateCourseBody.renewalPrice.toString())
if(updateCourseBody.level !== undefined) {
 formData.append('level', updateCourseBody.level)
 }
if(updateCourseBody.expirationDays !== undefined) {
 formData.append('expirationDays', updateCourseBody.expirationDays.toString())
 }
if(updateCourseBody.imageUrl !== undefined) {
 formData.append('imageUrl', updateCourseBody.imageUrl)
 }

      return customInstance<ObjectSuccess>(
      {url: `/api/courses/${courseId}`, method: 'PATCH',
      headers: {'Content-Type': 'multipart/form-data', },
       data: formData
    },
      options);
    }
  


